            AppRoutes = """["/approvals"]""",
            Tags = """["approvals","workflow","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"ap1","text":"What does the Inbox tab on the Approvals page show?","options":[{"id":"a","text":"Every approval request in the entire system, regardless of who it's assigned to"},{"id":"b","text":"Your personal queue of pending requests awaiting your decision","isCorrect":true},{"id":"c","text":"A read-only history of all approvals you have ever made"},{"id":"d","text":"The list of workflow definitions you can edit"}],"explanation":"The Inbox tab is each user's personal queue — it lists the pending approval requests that are waiting on that user's decision. It's available to all users, unlike the Workflows tab."},{"id":"ap2","text":"Who can see and use the Workflows tab?","options":[{"id":"a","text":"All authenticated users"},{"id":"b","text":"Only Admins and Managers","isCorrect":true},{"id":"c","text":"Only the user who submitted the request"},{"id":"d","text":"Anyone with a pending request in their inbox"}],"explanation":"The Workflows tab — where approval chains are defined — is visible only to Admins and Managers. Everyone can use the Inbox tab, but configuring workflows is restricted."},{"id":"ap3","text":"You click Approve on a request that is at step 2 of a 3-step workflow. What happens?","options":[{"id":"a","text":"The request is immediately marked Approved and completed"},{"id":"b","text":"The request advances to step 3 and waits for the next approver","isCorrect":true},{"id":"c","text":"The request is sent back to step 1 for re-review"},{"id":"d","text":"Nothing happens until all three approvers click Approve simultaneously"}],"explanation":"Approving advances the request to the next step in the chain. It only becomes Approved/completed when the final step is approved. Here, approving step 2 moves it to step 3."},{"id":"ap4","text":"What is required to reject a request from the inbox?","options":[{"id":"a","text":"Nothing — you just click the Reject button"},{"id":"b","text":"A reason/comment must be entered before the rejection can be confirmed","isCorrect":true},{"id":"c","text":"Manager approval before your rejection takes effect"},{"id":"d","text":"You must first delegate it to another user"}],"explanation":"Rejecting opens a dialog with a required reason field (up to 1000 characters). The confirm button stays disabled until you enter a reason. A rejected request is terminal."},{"id":"ap5","text":"A request shows the status 'AutoApproved'. Why?","options":[{"id":"a","text":"An administrator manually approved it on the requester's behalf"},{"id":"b","text":"The request amount fell below a step's auto-approve-below threshold, so the step approved automatically","isCorrect":true},{"id":"c","text":"The request was approved by every approver at the same time"},{"id":"d","text":"It was approved after the escalation window expired"}],"explanation":"A step can have an auto-approve-below amount. When the request's amount is under that value, the step is approved automatically and the request shows as AutoApproved — small amounts don't tie up an approver."},{"id":"ap6","text":"In a workflow step, what does the Approver Type 'Manager' mean?","options":[{"id":"a","text":"The request goes to anyone with the Manager role"},{"id":"b","text":"The request goes to the requester's direct manager","isCorrect":true},{"id":"c","text":"The request is approved automatically without review"},{"id":"d","text":"The request goes to the most senior manager in the company"}],"explanation":"Approver Type 'Manager' routes the request to the requester's direct manager. This differs from 'Role' (which routes to anyone holding a named role like Admin or Manager) and 'Specific User' (one named person)."},{"id":"ap7","text":"What is the purpose of a step's 'Escalate After (Hours)' setting?","options":[{"id":"a","text":"It auto-rejects the request after the given hours"},{"id":"b","text":"It auto-escalates the request if the step sits pending longer than the configured hours","isCorrect":true},{"id":"c","text":"It delays the request from appearing in the inbox for that many hours"},{"id":"d","text":"It sets how long the approver has to read the request before it locks"}],"explanation":"Escalate After (Hours) prevents requests from stalling. If a step remains pending past the configured window, the request auto-escalates (status Escalated) rather than sitting indefinitely."},{"id":"ap8","text":"Which of these entity types can be routed through an approval workflow?","options":[{"id":"a","text":"Only Purchase Orders"},{"id":"b","text":"Purchase Orders, Expenses, Quotes, Time Entries, and Sales Orders","isCorrect":true},{"id":"c","text":"Only financial documents like invoices and payments"},{"id":"d","text":"Any entity in the system, with no restrictions"}],"explanation":"Approval workflows support five entity types: Purchase Order, Expense, Quote, Time Entry, and Sales Order. Each workflow targets one entity type. Time entries have no amount, which is why the inbox shows a dash in the Amount column for them."},{"id":"ap9","text":"What does delegating a request do?","options":[{"id":"a","text":"It approves the request on the current approver's behalf"},{"id":"b","text":"It hands the decision to another user while the request stays at the same step","isCorrect":true},{"id":"c","text":"It cancels the request and starts a new workflow"},{"id":"d","text":"It moves the request back to the requester for changes"}],"explanation":"Delegation transfers the decision to another user without advancing the chain — the request remains at the same step, now under the delegate. The decision history records who it was delegated to."},{"id":"ap10","text":"A workflow has an Amount Threshold of $500. A $300 purchase order is submitted. What happens?","options":[{"id":"a","text":"The PO is rejected for being under the threshold"},{"id":"b","text":"The workflow does not activate for that PO because it's below the activation threshold","isCorrect":true},{"id":"c","text":"The PO is escalated immediately"},{"id":"d","text":"The PO must be manually approved by an Admin"}],"explanation":"An Amount Threshold makes the workflow activate only above that dollar amount. A $300 PO is below the $500 threshold, so the workflow doesn't trigger and the PO doesn't require this approval chain."},{"id":"ap11","text":"In the inbox, the Amount column shows a dash for a request. What does that mean?","options":[{"id":"a","text":"The amount has been hidden for privacy"},{"id":"b","text":"The entity has no associated amount — for example, a time entry","isCorrect":true},{"id":"c","text":"The request has already been approved"},{"id":"d","text":"The amount will appear only after the first approval"}],"explanation":"Not every entity has a financial amount. Time entries, for instance, have no amount, so the Amount column displays a dash. Financial entities like POs and expenses show a currency value."},{"id":"ap12","text":"You're building a workflow and try to save with no steps defined. What happens?","options":[{"id":"a","text":"It saves with a default single step added automatically"},{"id":"b","text":"The Save button is disabled until the workflow has at least one step","isCorrect":true},{"id":"c","text":"It saves but the workflow stays Inactive"},{"id":"d","text":"It saves and routes everything straight to an Admin"}],"explanation":"A workflow must have at least one step. The Save/Create button stays disabled until the form is valid and there is at least one step, so you can't create an empty approval chain."}]}"""
